import hashlib
from pathlib import Path
import re

def calculate_hash(dependency):
    """Calculate the SHA256 hash of a file."""
    with open(dependency, 'rb') as f:
        return hashlib.sha256(f.read()).hexdigest()

def update_dependencies(filename='requirements.txt', version=None):
    """Update dependencies in requirements.txt"""
    
    # Read file content into lines
    with open(filename, 'r') as f:
        lines = f.readlines()

    # Update each line to add hash
    for i, line in enumerate(lines):
        if line.startswith('-e'):  # This is a development requirement (link)
            continue
        
        match = re.search(r'([\w\.-]+)(?:\s*==\s*([\d\.]+))?', line.strip())
        if not match:  # Skip lines that don't represent a dependency
            continue
            
        name, existing_version = match.groups()
        
        if version and (not existing_version or version != existing_version):
            requirement = Path(name)
            if requirement.is_dir():  # This is a package from source control
                hash_value = calculate_hash(requirement)
                lines[i] = f'{name} @ {hash_value}\\n'
            else:
                lines[i] = f'{name}=={version}\\n'
    
    # Write file content back, replacing the old file with updated dependencies
    with open(filename, 'w') as f:
        f.writelines(lines)

# Update requirements to a specific version
update_dependencies('requirements.txt', '1.0.0')